BASE = "http://hr-app"

def test_reset_password_at_30min_boundary_expires(http_session, employee_credentials):
    token = <create_token_aged_minutes>(employee_credentials["user_id"], age_minutes=30)
    new_pw = "Boundary@P4ssw0rd"

    resp = http_session.post(
        f"{BASE}/password/reset",
