import pytest
import requests

BASE = "http://hr-app"

@pytest.mark.parametrize("bad_pw,violation", [
    ("short1!", "too_short"),
    ("alllowercasewithoutdigits!", "no_uppercase"),
    ("NoSpecialChar1234", "no_special"),
])
def test_reset_password_policy_violation_rejected(bad_pw, violation, valid_reset_token, employee_credentials, http_session):
    token = valid_reset_token["token"]

    resp = http_session.post(
        f"{BASE}/password/reset",
        json={"token": token, "password": bad_pw}
    )
    assert resp.status_code == 422, f"Expected 422 for violation={violation}, got {resp.status_code}"
    errors = resp.json().get("errors", [])
    assert len(errors) > 0, "Response must enumerate policy violations"

    auth = http_session.post(
        f"{BASE}/auth/login",
        json={"username": employee_credentials["username"], "password": employee_credentials["password"]}
    )
    assert auth.status_code == 200, "Original password must still be valid"

import pytest
import requests

BASE = "http://hr-app"

def test_reset_password_rate_limit_enforced(rate_limit_config, employee_credentials, token_factory, http_session):
    limit = rate_limit_config["password_reset_limit"]
    responses = []

    for i in range(limit):
        token = token_factory.create_fresh(employee_credentials["user_id"])
        resp = http_session.post(
            f"{BASE}/password/reset",
            json={"token": token, "password": f"Valid@P4ssw0rd{i}"}
        )
        responses.append(resp.status_code)

    assert all(s != 429 for s in responses), (
        f"Requests within limit must not be rate-limited; got statuses {responses}"
    )

    extra_token = token_factory.create_fresh(employee_credentials["user_id"])
    over_limit_resp = http_session.post(
        f"{BASE}/password/reset",
        json={"token": extra_token, "password": "Valid@P4ssw0rdExtra"}
    )
    assert over_limit_resp.status_code == 429, (
        f"Expected 429 on attempt {limit + 1}, got {over_limit_resp.status_code}"
    )
    assert "Retry-After" in over_limit_resp.headers, "429 response must include Retry-After header"

    <teardown_rate_limit_state>(employee_credentials["user_id"])
